import React, { useState } from 'react';
import { FaThumbsUp, FaThumbsDown, FaReply, FaTrash, FaFlag, FaEdit, FaCheck, FaTimes } from 'react-icons/fa';
import Avatar from './Avatar';
import dayjs from 'dayjs';
import relativeTime from 'dayjs/plugin/relativeTime';
import { formatDistanceToNow } from 'date-fns';
import { toast } from 'react-toastify';

dayjs.extend(relativeTime);

const CommentItem = ({ comment, postId, currentUser, onReply, onDelete, onVote, onEdit }) => {
  const [showReplies, setShowReplies] = useState(true);
  const [reportModalOpen, setReportModalOpen] = useState(false);
  const [reportReason, setReportReason] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [editText, setEditText] = useState(comment.text || comment.content);
  const [isDeleting, setIsDeleting] = useState(false);
  
  const isAuthor = currentUser && comment.author._id === currentUser._id;
  const hasReplies = comment.replies && comment.replies.length > 0;
  
  const handleReportSubmit = (e) => {
    e.preventDefault();
    // Implement report functionality when backend is ready
    console.log('Reporting comment:', comment._id, 'Reason:', reportReason);
    setReportModalOpen(false);
    setReportReason('');
  };

  const handleEdit = () => {
    setIsEditing(true);
    setEditText(comment.text || comment.content);
  };
  
  const cancelEdit = () => {
    setIsEditing(false);
  };
  
  const saveEdit = async () => {
    if (!editText.trim()) {
      toast.error('Comment cannot be empty');
      return;
    }
    
    try {
      if (onEdit) {
        await onEdit(comment._id, editText);
      }
      setIsEditing(false);
    } catch (error) {
      console.error('Error updating comment:', error);
      toast.error('Failed to update comment');
    }
  };
  
  const handleDelete = async () => {
    if (!isDeleting) {
      setIsDeleting(true);
      return;
    }
    
    try {
      await onDelete(comment._id);
    } catch (error) {
      console.error('Error deleting comment:', error);
      toast.error('Failed to delete comment');
      setIsDeleting(false);
    }
  };
  
  const handleReply = () => {
    if (onReply) {
      onReply(comment.author.name);
    }
  };
  
  const formatTime = (date) => {
    return formatDistanceToNow(new Date(date), { addSuffix: true });
  };

  return (
    <div className="flex space-x-3 p-4 bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700">
      <img 
        src={comment.author?.profilePicture || 'https://via.placeholder.com/40'} 
        alt={comment.author?.name || 'Anonymous'} 
        className="w-10 h-10 rounded-full" 
      />
      
      <div className="flex-1">
        <div className="flex justify-between items-start">
          <div>
            <h4 className="font-medium text-gray-900 dark:text-white">
              {comment.author?.name || 'Anonymous'}
            </h4>
            <p className="text-xs text-gray-500 dark:text-gray-400">
              {formatTime(comment.createdAt)}
              {comment.createdAt !== comment.updatedAt && ' (edited)'}
            </p>
          </div>
          
          <div className="flex space-x-2">
            {currentUser && !isAuthor && (
              <button
                onClick={() => setReportModalOpen(true)} 
                className="text-gray-400 hover:text-red-500"
                title="Report comment"
              >
                <FaFlag size={12} />
              </button>
            )}
            
            {isAuthor && (
              <>
                <button 
                  onClick={isEditing ? cancelEdit : handleEdit}
                  className="text-gray-500 hover:text-blue-500 dark:text-gray-400 dark:hover:text-blue-400"
                >
                  {isEditing ? <FaTimes /> : <FaEdit />}
                </button>
                
                <button 
                  onClick={handleDelete}
                  className={`${isDeleting ? 'text-red-500 dark:text-red-400' : 'text-gray-500 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400'}`}
                >
                  <FaTrash />
                </button>
              </>
            )}
          </div>
        </div>
        
        {isEditing ? (
          <div className="mt-2">
            <textarea
              value={editText}
              onChange={(e) => setEditText(e.target.value)}
              className="w-full px-3 py-2 text-gray-700 dark:text-gray-200 border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
              rows="3"
            ></textarea>
            
            <div className="flex justify-end mt-2 space-x-2">
              <button
                onClick={cancelEdit}
                className="px-3 py-1 bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded hover:bg-gray-300 dark:hover:bg-gray-600"
              >
                Cancel
              </button>
              <button
                onClick={saveEdit}
                className="px-3 py-1 bg-blue-600 text-white rounded hover:bg-blue-700"
              >
                Save
              </button>
            </div>
          </div>
        ) : (
          <div className="mt-2 text-gray-700 dark:text-gray-300 whitespace-pre-line">
            {comment.text || comment.content}
          </div>
        )}
        
        <div className="flex items-center mt-2 space-x-4">
          <div className="flex items-center text-sm">
            <button
              onClick={() => onVote(comment._id, 'upvote')}
              className={`p-1 ${
                comment.userVote === 'upvote' ? 'text-green-600' : 'text-gray-400 hover:text-green-600'
              }`}
              title="Upvote"
            >
              <FaThumbsUp size={12} />
            </button>
            <span className="mx-1 text-xs">{comment.upvotes || 0}</span>
          </div>
          
          <div className="flex items-center text-sm">
            <button
              onClick={() => onVote(comment._id, 'downvote')}
              className={`p-1 ${
                comment.userVote === 'downvote' ? 'text-red-600' : 'text-gray-400 hover:text-red-600'
              }`}
              title="Downvote"
            >
              <FaThumbsDown size={12} />
            </button>
            <span className="mx-1 text-xs">{comment.downvotes || 0}</span>
          </div>
          
          {currentUser && (
            <button
              onClick={handleReply}
              className="text-xs text-gray-500 hover:text-green-600 flex items-center"
            >
              <FaReply size={12} className="mr-1" /> Reply
            </button>
          )}
          
          {hasReplies && (
            <button
              onClick={() => setShowReplies(!showReplies)}
              className="text-xs text-blue-600 hover:underline"
            >
              {showReplies ? 'Hide replies' : `Show ${comment.replies.length} ${comment.replies.length === 1 ? 'reply' : 'replies'}`}
            </button>
          )}
        </div>
        
        {/* Replies */}
        {hasReplies && showReplies && (
          <div className="mt-3 pl-4 border-l-2 border-gray-100 space-y-3">
            {comment.replies.map(reply => (
              <CommentItem
                key={reply._id}
                comment={reply}
                postId={postId}
                currentUser={currentUser}
                onReply={onReply}
                onDelete={onDelete}
                onVote={onVote}
              />
            ))}
          </div>
        )}
        
        {isDeleting && !isEditing && (
          <div className="mt-2 p-2 bg-red-50 dark:bg-red-900/30 rounded text-sm">
            <p className="text-red-600 dark:text-red-300 mb-2">Are you sure you want to delete this comment?</p>
            <div className="flex justify-end space-x-2">
              <button
                onClick={() => setIsDeleting(false)}
                className="px-3 py-1 bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded hover:bg-gray-300 dark:hover:bg-gray-600"
              >
                Cancel
              </button>
              <button
                onClick={handleDelete}
                className="px-3 py-1 bg-red-600 text-white rounded hover:bg-red-700"
              >
                Delete
              </button>
            </div>
          </div>
        )}
      </div>
      
      {/* Report Modal */}
      {reportModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-lg max-w-md w-full p-6">
            <h3 className="text-xl font-bold mb-4">Report Comment</h3>
            <form onSubmit={handleReportSubmit}>
              <div className="mb-4">
                <label htmlFor="reportReasonComment" className="block text-gray-700 mb-2">
                  Why are you reporting this comment?
                </label>
                <textarea
                  id="reportReasonComment"
                  value={reportReason}
                  onChange={(e) => setReportReason(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded"
                  rows="4"
                  placeholder="Please explain why you're reporting this comment..."
                  required
                ></textarea>
              </div>
              <div className="flex justify-end space-x-3">
                <button
                  type="button"
                  onClick={() => setReportModalOpen(false)}
                  className="px-4 py-2 bg-gray-200 text-gray-800 rounded hover:bg-gray-300"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700"
                >
                  Report
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CommentItem;
